import { useEffect, useState } from 'react'

import { Link, Outlet, useLocation } from 'react-router-dom'

import { Add as AddIcon } from '@mui/icons-material'
import { Container, Box, Button, Stack, CircularProgress, Alert, Typography } from '@mui/material'

import { getTrainingPlans } from '@/api/trainingPlans'
import { routes } from '@/routes'
import type { TrainingPlan } from '@/types/database'

import PlanCard from './components/PlanCard'

export function PlansPage() {
  const location = useLocation()
  const isListView = location.pathname === '/plans' || location.pathname === '/plans/'

  return (
    <Container maxWidth="md">
      <Box sx={{ my: 4 }}>
        <Box
          sx={{
            display: 'flex',
            justifyContent: 'space-between',
            alignItems: 'center',
            mb: 3,
          }}
        >
          <Box></Box>
          {/* <Typography variant="h4" component="h1">
            훈련 계획
          </Typography> */}
          {isListView && (
            <Button
              component={Link}
              to={routes.plans.new.$()}
              variant="contained"
              startIcon={<AddIcon />}
            >
              새 계획
            </Button>
          )}
        </Box>
        {isListView ? <PlansList /> : <Outlet />}
      </Box>
    </Container>
  )
}

function PlansList() {
  const [plans, setPlans] = useState<TrainingPlan[]>([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    loadPlans()
  }, [])

  async function loadPlans() {
    try {
      setLoading(true)
      const data = await getTrainingPlans()
      setPlans(data)
    } catch (err) {
      setError('훈련 계획을 불러오는데 실패했습니다.')
      // eslint-disable-next-line no-console
      console.error(err)
    } finally {
      setLoading(false)
    }
  }

  if (loading) {
    return (
      <Box sx={{ display: 'flex', justifyContent: 'center', py: 4 }}>
        <CircularProgress />
      </Box>
    )
  }

  if (error) {
    return <Alert severity="error">{error}</Alert>
  }

  if (plans.length === 0) {
    return <Alert severity="info">아직 훈련 계획이 없습니다. 새 계획을 만들어보세요!</Alert>
  }

  const activePlans = plans.filter((p) => !p.completed_at)
  const completedPlans = plans.filter((p) => p.completed_at)

  return (
    <Stack spacing={2}>
      {activePlans.map((plan) => (
        <PlanCard key={plan.id} plan={plan} variant="list" />
      ))}
      {completedPlans.length > 0 && (
        <>
          <Typography variant="body2" color="text.secondary" sx={{ pt: 1 }}>
            완료된 계획
          </Typography>
          {completedPlans.map((plan) => (
            <PlanCard key={plan.id} plan={plan} variant="list" />
          ))}
        </>
      )}
    </Stack>
  )
}
